const keyOf = (x: number, y: number): string => `${x},${y}`;

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveKeys = new Set(cells.map(([x, y]) => keyOf(x, y)));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      const key = keyOf(nx, ny);
      const prevCount = neighborCounts.get(key)?.count ?? 0;
      neighborCounts.set(key, { cell: [nx, ny], count: prevCount + 1 });
    }
  }

  const nextCells: Cell[] = [];
  for (const [key, { cell, count }] of neighborCounts) {
    const survives = count === 2 && liveKeys.has(key);
    const reproduces = count === 3;
    if (survives || reproduces) {
      nextCells.push(cell);
    }
  }
  return nextCells;
}

