const keyOf = (x: number, y: number): string => `${x},${y}`;

const isAlive = (neighborCount: number, wasAlive: boolean): boolean =>
  neighborCount === 3 || (neighborCount === 2 && wasAlive);

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveKeys = new Set(cells.map(([x, y]) => keyOf(x, y)));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const key = keyOf(neighbor[0], neighbor[1]);
      const entry = neighborCounts.get(key);
      neighborCounts.set(key, { cell: neighbor, count: (entry?.count ?? 0) + 1 });
    }
  }

  const nextCells: Cell[] = [];
  for (const [key, { cell, count }] of neighborCounts) {
    if (isAlive(count, liveKeys.has(key))) {
      nextCells.push(cell);
    }
  }
  return nextCells;
}
